/* Mise à jour du déplacement du robot virtuel sur la carte
Source des données : la fonction récursive qui suit les étapes
construites dans le flow cible en fonction de l'état d'avancement réel du robot
capté par les encodeurs et transmise par l'arduino dans les variables rzX et RzY.
La  fonction ci-dessous agit couplé avec une fonction qui injecte les données dans le svg de la carte
situé dans le flow Rz-Suivi-Salon. La modif de l'une doit entrainer l'actualisation de l'autre
une variante existe utilisatant la fonction matrix au lieu de translate et rotate.*/

var rzXCarte= global.get("rzX")/10;// passage mm en cm
var rzYCarte= global.get("rzY")/10;
var defEtape = global.get("defEtape");
//xini,yini,xcible,ycible - hormis première valeur source arduino basé sur rxX et rzY
// global.set("defEtape", [iniEtapeX,iniEtapeY,cibleEtapeX,cibleEtapeY]);
var xIni=defEtape[0];
var yIni=defEtape[1];
var xCible=defEtape[2];
var yCible=defEtape[3];
//variable fourni à la carte
var rzTransform;
//Cas DEPLACEMENT PAR ANGLE DROIT AVEC ETAPE

if (yCible==yIni && yIni===0) {//déplacement sur x avec y O pour eviter obstacle on doit être sur axe principal
   if (xCible>=xIni){//sens déplacement gauche vers droite 
       rzTransform="translate("+ rzXCarte +", " + rzYCarte+")";//penser à l'espace après la virgule ds les val des couples
    }
   else { //demi-tour droite à gauche sur axe x vers che rotate -180  par la gauche (par droite 180)
       //angle par rapport au pt origine def par deplacement translate avec correction pour tenir compte de la taille de rZ (rotation sur angle forme)
       rzTransform="translate("+ rzXCarte +", " + rzYCarte+") rotate("+ -180+ ", "+ 0 + ", "+ 30 + ")" ;
    }
}// fin deplacement sur x avec y à 0

// déplacement sur Y
else if (xCible==xIni && yCible>=yIni){
    //gauche à droite et vers le bas de la carte voir en biais ds la même direction
       rzTransform="translate("+ rzXCarte +", " + rzYCarte+") rotate("+ 90+ ", "+ 0 + ", "+ 30 + ")" ;
}
else if (xCible==xIni && yCible<=yIni){
       rzTransform="translate("+ rzXCarte +", " + rzYCarte+") rotate("+ -90+ ", "+ 0 + ", "+ 30 + ")" ;
}        

// déplacement en biais uniquement pour ajustement (sinon couperait ds les obstacles)
/*Trigonometrie :  
angle en degre = angleenradian x 180 /pi
tangented'un angle en radiant = coté opposé sur coté adjacent   (n'utilise pas hypothénuse)
soit tang angle en rad = x/y
*/
else{
    //conv radian en degre
    var pi = Math.PI;    
    var radians;
    var radians_to_degrees= radians*(57.2957795);//180/pi
    //quatre types de déplacement en biais
    if      (xCible>=xIni && yCible>=yIni){
            radians=rzYCarte/rzXCarte;//opposé sur adjacent
            radians_to_degrees= radians*(57.2957795);
            rzTransform="translate("+ rzXCarte +", " + rzYCarte+") rotate("+ radians_to_degrees+ ", "+ 0 + ", "+ 30 + ")" ;
    }
    else if (xCible>=xIni && yCible<=yIni){
            radians=rzYCarte/rzXCarte;//opposé sur adjacent
            radians_to_degrees= radians*(57.2957795);
            rzTransform="translate("+ rzXCarte +", " + rzYCarte+") rotate("+ -radians_to_degrees+ ", "+ 0 + ", "+ 30 + ")" ;
    }
    else if (xCible<=xIni && yCible>=yIni){
            radians=rzXCarte/rzYCarte;//opposé sur adjacent
            radians_to_degrees= radians*(57.2957795);
            rzTransform="translate("+ rzXCarte +", " + rzYCarte+") rotate("+ radians_to_degrees+ ", "+ 0 + ", "+ 30 + ")" ;
    }
    else if (xCible<=xIni && yCible<=yIni){
            radians=rzXCarte/rzYCarte;//opposé sur adjacent
            radians_to_degrees= radians*(57.2957795);
            rzTransform="translate("+ rzXCarte +", " + rzYCarte+") rotate("+ -radians_to_degrees+ ", "+ 0 + ", "+ 30 + ")" ;
    }
    else {
        msg={topic:"Erreur"};
    }
}
global.set("rzTransform",rzTransform);
msg={payload: rzTransform};
return msg;

var rZxCarte= global.get("rzX")/10;// passage mm en cm
var rZyCarte= global.get("rzY")/10;
var xcible = global.get("constRzXcible");
var ycible = global.get("constRzYcible");
var xini = global.get("constRzXini");
var yini = global.get("constRzYini");
var matriceRzPosInSvg;
//Etape prepa donne pour position rz courante à la carte
// pour etablir les vars de la fonction matrix de transform SVG on prend la commande et non le retour de la position
if (ycible==yini && yini===0) {//déplacement sur x
   if (xcible>=xini){//sens déplacement gauche vers droite 
       //penser à l'espace après la virgule ds les val des couples
      matriceRzPosInSvg="matrix(1, 0, 0, 1, "+ rZxCarte +", " + rZyCarte+")"
       }
   else { //déplacement droite à gauche vers che
       matriceRzPosInSvg="matrix(-1, 0, 0, 1, "+ rZxCarte +", " + rZyCarte+")";
       }//fin else droite à gauche
}//fin du tt droit
else{//voir si facteur de correction lorsque correction -33 ou +33
    if(xcible>=xini && ycible>=yini){//gauche à droite et vers le bas de la carte
     matriceRzPosInSvg="matrix(1, 1, -1, 1, " + rZxCarte +", " + rZyCarte+")";
     }
     else if(xcible>=xini && ycible<=yini){//gauche à droite et monte sur la carte (val négative)
      matriceRzPosInSvg="matrix(-1, -1, 1, 1, "+ rZxCarte +", " + rZyCarte+")";
     }
    else if(xcible<=xini && ycible>=yini){//droite à gauche et descend sur la carte (val positive)
      matriceRzPosInSvg="matrix(-1, -1, 1, 1, "+ rZxCarte +", " + rZyCarte+")";
     }        
     else if(xcible<=xini && ycible<=yini){//droite à gauche et descend sur la carte (val positive)
      matriceRzPosInSvg="matrix(-1, 1, -1, 1, "+ rZxCarte +", " + rZyCarte+")";
     }        
    }//fin de tourne


global.set("matriceRzPosInSvg",matriceRzPosInSvg);
msg=null;
return msg;

